 98→    public function interviewSchedule($day, $rpid): array
 99→    {
100→        $userId = AuthRecord::user()->user_id;
101→        $iwms = InterviewRecordsMd::alias('ir')
102→            ->join('recruitment_procession as rp', 'ir.rec_pro_id', '=', 'rp.id')
103→            ->leftJoin('jobs as b', 'b.job_id', 'rp.job_id')
104→            ->leftJoin('job_departments as d', 'd.department_id', 'b.department_id')
105→            ->leftJoin('offer_approval as oa', 'rp.id', 'oa.rec_pro_id')
106→            ->where('ir.interviewer_id', '=', $userId)
107→            ->where(function ($query) use ($day) {
108→                $query->where('ir.updated_at', '>=', date('Y-m-d H:i:s', strtotime("-{$day} day")))
109→                    ->orWhere('ir.interview_time', '>=', date('Y-m-d H:i:s', strtotime("-{$day} day")));
110→            });
111→        if ($rpid) {
112→            $iwms->where('ir.rec_pro_id', $rpid);
113→        }
114→        $interviewRecords = $iwms
115→            ->selectRaw("rp.resume_id,rp.filled_reason,rp.status as rec_pro_status, rp.id as rec_pro_id , ir.*, CONCAT(d.department_name,'-',b.job_name) as job_name, ifnull(oa.approval_status, '') as approval_status, rp.job_id as rp_job_id")
116→            ->get()->toArray();
117→
118→        [$interviewRecords, $tokens] = $this->filterAddToken($interviewRecords);
119→
120→        $resumeIds = array_column($interviewRecords, 'resume_id');
121→        $recProIds = array_column($interviewRecords, 'rec_pro_id');
122→        // 加入以简历为准的, 标为当前的笔试的信息
123→        $resumeList = ResumeMd::whereIn('id', $resumeIds)->selectRaw('id as resume_id, username, nickname, inputer_user_id, recent_archive_info')
124→            ->get()->toArray();
125→
126→        $offerMap = ResumeRecruitmentCacheMd::whereIn('resume_id', $resumeIds)->where('type', 'create_offer')
127→            ->selectRaw('max(created_at) as created_at, resume_id')->groupBy('resume_id')->get()->keyBy('resume_id')->toArray();
128→        $entryMap = WaitingEntryMd::whereIn('rec_pro_id', $recProIds)->select(['entry_time', 'rec_pro_id', 'remark'])->get()->keyBy('rec_pro_id')->toArray();
129→
130→        foreach ($interviewRecords as $k => $v) {
131→            $interviewRecords[$k]['username'] = '';
132→            $interviewRecords[$k]['inputer_user_id'] = '';
133→            // 只保留到日期
134→            $createdAt = $offerMap[$v['resume_id']]['created_at'] ?? '';
135→            $interviewRecords[$k]['createOfferTime'] = $createdAt ? date('Y-m-d', strtotime($createdAt)) : '';
136→            $interviewRecords[$k]['remark'] = $entryMap[$v['rec_pro_id']]['remark'] ?? '';
137→            $interviewRecords[$k]['entry_time'] = $entryMap[$v['rec_pro_id']]['entry_time'] ?? '';
138→            if ($interviewRecords[$k]['rec_pro_status'] == 'archive') {
139→                $interviewRecords[$k]['entry_time'] = '';
140→            }
141→            foreach ($resumeList as $rv) {
142→                if ($rv['resume_id'] == $v['resume_id']) {
143→                    $interviewRecords[$k]['username'] = $rv['username'];
144→                    $interviewRecords[$k]['nickname'] = $rv['nickname'];
145→                    $recent_archive_info = $rv['recent_archive_info'];
146→                    $interviewRecords[$k]['archive_reason'] = $recent_archive_info['reason'] ?? $v['filled_reason'] ?? '';
147→                    $interviewRecords[$k]['specific_reason'] = $recent_archive_info['remark'] ?? '';
148→                    $interviewRecords[$k]['inputer_user_id'] = $rv['inputer_user_id'];
149→                }
150→            }
151→        }
152→        $list = WrittenExamMd::alias('we')->with('FileStorePathInfo')->join('recruitment_procession as rp', 'we.rec_pro_id', '=', 'rp.id')
153→            ->whereIn('rp.resume_id', $resumeIds)->where('we.is_closed', 0)
154→            ->where('we.is_current', 1)->selectRaw('we.*, rp.resume_id')->get()->toArray();
155→        foreach ($interviewRecords as $k => $v) {
156→            $interviewRecords[$k]['exam_list'] = [];
157→            foreach ($list as $lv) {
158→                if ($lv['resume_id'] == $v['resume_id']) {
159→                    $interviewRecords[$k]['exam_list'][] = $lv;
160→                }
161→            }
162→        }
163→
164→        return ['interview_records' => $interviewRecords, 'decrypt_config' => ['tokens' => $tokens]];
165→    }
