283→                $recruitment['waiting_entry'] = Arr::only($recruitment['waiting_entry'], ['rec_pro_id', 'entry_time', 'entry_job_name', 'supervisor_id', 'mentor', 'seat', 'remark', 'follow_up_hr_id', 'work_schedule', 'is_overseas_student', 'is_intern', 'is_part_time', 'work_place', 'work_type', 'is_foreigner', 'is_hmt', 'is_tripartite_agreement_signed', 'is_social_recruitment']);
284→                $recruitment['waiting_entry']['supervisor'] = Arr::get($users, "{$recruitment['waiting_entry']['supervisor_id']}.nickname", '');
285→            }
