291→    public function addToken($resumes, $resume_id)
292→    {
293→        return array_values(array_filter(array_map(function ($re) use ($resume_id) {
294→            $re['token'] = getAuthorityToken(AuthRecord::user()->user_id, $resume_id ?? $re['resume_id']);
295→            return $re; // 更新工作年份及年龄
296→        }, $resumes), function ($re) {
297→            return $re['token'] !== null;
298→        }));
299→    }
