301→    protected function filterToken($recruitments)
302→    {
303→        $tokens = [];
304→        $newRecs = array_values(array_filter($recruitments, function ($ir) use (&$tokens) {
305→            $token = getAuthorityToken(AuthRecord::user()->user_id, $ir['resume_id']);
306→            $tokens[] = $token;
307→            return $token !== null;
308→        }));
309→
310→        return [$newRecs, array_values(array_unique(array_filter($tokens)))];
311→    }
