329→    /**
330→     * 根据描述算出年份，向下取整.
331→     *
332→     * @param int $seconds
333→     * @return string
334→     */
335→    protected function getYearBySecond(int $seconds)
336→    {
337→        $result = __('my_api.none');
338→        if ($seconds >= 86400 * 365) {
339→            $year = floor($seconds / (86400 * 365));
340→            $result = $year.__('my_api.year');
341→        }
342→        return $result;
343→    }
