 * @param array|int|string $authorizedPerson
 * @param array|int|string $item
 * @param string $type
 * @return null|string
 */
function getAuthorityToken($authorizedPerson, $item, string $type = 'resume'): ?string
{
    $time = now()->format('Y-m-d H:i:s');

    $authorizedPersonSearch = is_array($authorizedPerson) ? ($authorizedPerson[0] ?? []) : $authorizedPerson;
    $itemSearch = is_array($item) ? $item[0] : $item;

    is_string($authorizedPersonSearch) && $authorizedPersonSearch = "\"{$authorizedPersonSearch}\"";
    is_string($itemSearch) && $itemSearch = "'{$itemSearch}'";
    $token = AuthorityTokenMd::when($authorizedPersonSearch !== [], function ($query) use ($authorizedPersonSearch) {
        $query->where('authorized_person', 'REGEXP', "(\\[|,){$authorizedPersonSearch}(\\]|,)");
    })
        ->where('item', 'REGEXP', "(\\[|,){$itemSearch}(\\]|,)")
        ->whereRaw("expire_time >= TIMESTAMPDIFF(SECOND,created_at,'{$time}')")
        ->where('type', $type)
        ->select('token', 'authorized_person', 'item')
        ->orderBy('id', 'desc')->get()->toArray();
    is_array($authorizedPerson) && $token = array_filter($token, function ($value) use ($authorizedPerson) {
        if (empty(array_diff($authorizedPerson, $value['authorized_person']))) {
            return true;
        }
        return false;
    });

    is_array($item) && $token = array_filter($token, function ($value) use ($item) {
        if (empty(array_diff($item, $value['item']))) {
            return true;
        }
        return false;
    });

    $token = array_values($token);
    if (!empty($token)) {
        return $token[0]['token'];
    }

    return null;
}

